export const getNhlProductPrice = (productId?: string): NhlProductPrice | undefined => {
  if (!productId) return undefined;

  const productPrice = NHL_PRODUCT_PRICES[productId];
  return productPrice ? { ...productPrice, currency: "USD" } : undefined;
};
